#!/usr/bin/env node
import { chmodSync, copyFileSync, mkdirSync, realpathSync, statSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { spawnSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';

const appDir = dirname(fileURLToPath(import.meta.url));
const gnosisRoot = join(appDir, '..', '..');
const openSourceRoot = join(gnosisRoot, '..');
const monorepoRoot = join(openSourceRoot, '..');
const outDir = join(appDir, '..', 'src-tauri', 'binaries');

function existingFile(path) {
  try {
    return statSync(path).isFile() ? realpathSync(path) : null;
  } catch {
    return null;
  }
}

function buildFatStationIfRequested() {
  if (process.env.MOONSHINE_BUILD_FAT_STATION !== '1') return;
  const result = spawnSync(
    'pnpm',
    ['run', 'a0', '--', 'run', 'distributed-inference:build-fat-station'],
    {
      cwd: monorepoRoot,
      stdio: 'inherit',
      env: process.env,
    }
  );
  if (result.status !== 0) {
    throw new Error(`distributed-inference:build-fat-station failed with exit ${result.status}`);
  }
}

function resolveSource(bin) {
  const sources = Array.isArray(bin.sources) ? bin.sources : [bin.source];
  for (const source of sources) {
    const found = existingFile(source);
    if (found) return found;
  }
  if (bin.name === 'fat-station') {
    buildFatStationIfRequested();
    for (const source of sources) {
      const found = existingFile(source);
      if (found) return found;
    }
  }
  return null;
}

const bins = [
  {
    name: 'moonshine',
    source: join(openSourceRoot, '.bin', 'moonshine'),
    required: true,
  },
  {
    name: 'monster-guard',
    sources: [
      join(openSourceRoot, '.bin', 'monster-guard'),
      join(gnosisRoot, 'monster-guard', 'target', 'release', 'monster-guard'),
      join(outDir, 'monster-guard'),
    ],
    required: true,
  },
  {
    name: 'wall',
    source: join(openSourceRoot, 'aeon', 'packages', 'wall', 'wall'),
  },
  {
    name: 'gnexec',
    source: join(gnosisRoot, 'polyglot', 'target', 'release', 'gnexec'),
  },
  {
    name: 'gnosis-polyglot',
    source: join(gnosisRoot, 'polyglot', 'target', 'release', 'gnosis-polyglot'),
  },
  {
    name: 'monster',
    source: join(gnosisRoot, 'polyglot', 'target', 'release', 'monster'),
  },
  {
    name: 'fat-station',
    sources: [
      process.env.FAT_STATION_BIN,
      join(gnosisRoot, 'distributed-inference', 'target', 'release', 'fat-station'),
      join(gnosisRoot, 'distributed-inference', 'target', 'debug', 'fat-station'),
      join(outDir, 'fat-station'),
    ].filter(Boolean),
  },
  {
    name: 'rip',
    source: join(openSourceRoot, '.bin', 'rip'),
  },
  {
    name: 'bw',
    source: join(openSourceRoot, '.bin', 'bw'),
  },
];

mkdirSync(outDir, { recursive: true });

for (const bin of bins) {
  const source = resolveSource(bin);
  if (!source) {
    if (bin.required) {
      const sources = Array.isArray(bin.sources) ? bin.sources : [bin.source];
      throw new Error(`${bin.name}: no source found in ${sources.join(', ')}`);
    }
    const sources = Array.isArray(bin.sources) ? bin.sources : [bin.source];
    const hint = bin.name === 'fat-station' ? ' (set MOONSHINE_BUILD_FAT_STATION=1 to build it)' : '';
    console.warn(`skipped ${bin.name}: ${sources.join(', ')} not found${hint}`);
    continue;
  }
  const mode = statSync(source).mode;
  const target = join(outDir, bin.name);
  const existingTarget = existingFile(target);
  if (existingTarget !== source) {
    copyFileSync(source, target);
  }
  chmodSync(target, mode | 0o755);
  console.log(`prepared ${bin.name}: ${source} -> ${target}`);
}
